const platformAlertTypes={twitch:['follow','subscription','gift-subscription','cheer','raid'],youtube:['follow','membership','gift-subscription','super-chat'],kick:['follow','subscription','gift-subscription','gift'],tiktok:['follow','subscription','gift','milestone']};
const alertTypeLabels={follow:'Follow',subscription:'Subscription',membership:'Membership','gift-subscription':'Gift subscription',gift:'Gift',cheer:'Bits / Cheer','super-chat':'Super Chat / Sticker',raid:'Raid',milestone:'Like milestone'};
