function renderAlerts(){if(!state.alertSettings)return;const global=byId('alert-global-form');global.elements.maxAlertQueue.value=state.alertSettings.maxAlertQueue;global.elements.alertDurationMs.value=state.alertSettings.alertDurationMs;global.elements.showSimulated.checked=state.alertSettings.showSimulated;renderAlertTree()}
function renderAlertTree(){const profiles=state.alertSettings.alerts.profiles;const tree=byId('alert-tree');tree.innerHTML=Object.entries(platformAlertTypes).map(([platform,types])=>`<div class="alert-tree-platform"><h3>${safe(platformLabels[platform])}</h3><ul>${types.map((type)=>{const profile=profiles[platform]&&profiles[platform][type];const enabled=!profile||profile.enabled!==false;const active=state.selectedAlert&&state.selectedAlert.platform===platform&&state.selectedAlert.alertType===type;return `<li class="alert-tree-row"><input type="checkbox" ${enabled?'checked':''} data-toggle-alert="${platform}:${type}" aria-label="Enable ${safe(alertTypeLabels[type])} on ${safe(platformLabels[platform])}"><button type="button" class="alert-tree-item${active?' active':''}${enabled?'':' item-disabled'}" data-select-alert="${platform}:${type}">${safe(alertTypeLabels[type])}</button></li>`}).join('')}</ul></div>`).join('');tree.querySelectorAll('[data-select-alert]').forEach((button)=>button.addEventListener('click',()=>{const [platform,type]=button.dataset.selectAlert.split(':');selectAlertProfile(platform,type)}));tree.querySelectorAll('[data-toggle-alert]').forEach((input)=>input.addEventListener('change',async()=>{const [platform,type]=input.dataset.toggleAlert.split(':');const profiles=state.alertSettings.alerts.profiles;profiles[platform]=profiles[platform]||{};profiles[platform][type]={...(profiles[platform][type]||{}),enabled:input.checked};try{await stageAlerts();if(state.selectedAlert&&state.selectedAlert.platform===platform&&state.selectedAlert.alertType===type){selectAlertProfile(platform,type);byId('alert-state').textContent='Alert changes staged. Commit and restart StreamBridge to apply them.'}else renderAlertTree()}catch(error){byId('alert-state').textContent=error.message}}))}
function selectAlertProfile(platform,type){state.selectedAlert={platform,alertType:type};const form=byId('alert-profile-form');const profile=(state.alertSettings.alerts.profiles[platform]&&state.alertSettings.alerts.profiles[platform][type])||{};byId('alert-editor-title').textContent=`${platformLabels[platform]} · ${alertTypeLabels[type]}`;form.elements.enabled.checked=profile.enabled!==false;form.elements.priority.value=profile.priority||'';form.elements.durationMs.value=profile.durationMs||'';form.elements.titleTemplate.value=profile.titleTemplate||'';form.elements.detailTemplate.value=profile.detailTemplate||'';form.elements.soundMode.value=profile.sound?.mode||'none';form.elements.soundVolume.value=profile.sound?.volume??0.35;form.elements.customSoundUrl.value=profile.sound?.customUrl||'';form.elements.cardBackgroundColor.value=profile.card?.backgroundColor||'#171120';form.elements.cardFontFamily.value=profile.card?.fontFamily||'system';form.elements.cardLayout.value=profile.card?.layout||'classic';form.elements.cardMediaPlacement.value=profile.card?.mediaPlacement||'behind';form.elements.backgroundImageUrl.value=profile.card?.backgroundImageUrl||'';form.elements.backgroundVideoUrl.value=profile.card?.backgroundVideoUrl||'';form.elements.backgroundImageFile.value='';form.elements.backgroundVideoFile.value='';byId('clear-background-video').classList.toggle('hidden',!profile.card?.backgroundVideoUrl);form.elements.aggregationMode.value=profile.aggregation?.mode||'none';form.elements.aggregationWindowMs.value=profile.aggregation?.windowMs||5000;form.classList.remove('hidden');byId('alert-editor-empty').classList.add('hidden');byId('alert-state').textContent=`Editing ${platformLabels[platform]} · ${alertTypeLabels[type]}.`;renderAlertTree();renderAlertPreview()}
const previewTokenExamples={actor:'ExampleViewer',amount:'5.00',currency:'USD',quantity:'3',itemName:'Rose',tier:'Tier 1',message:'Thanks for the stream!',metric:'likes',value:'100'};
function fillPreviewTemplate(template,tokens){return template.replace(/\{(\w+)\}/g,(match,key)=>tokens[key]!==undefined&&tokens[key]!==''?tokens[key]:match)}
function buildPreviewMediaNode(videoUrl,imageUrl){if(videoUrl){const video=document.createElement('video');video.src=videoUrl;video.autoplay=true;video.loop=true;video.muted=false;video.playsInline=true;return video}const img=document.createElement('img');img.src=imageUrl;img.alt='';return img}
function renderAlertPreview(){if(!state.selectedAlert)return;const form=byId('alert-profile-form');const {platform,alertType}=state.selectedAlert;const tokens={...previewTokenExamples,alertType:alertTypeLabels[alertType]||alertType,platform};
  const titleTemplate=form.elements.titleTemplate.value||'{actor} sent {amount} {currency}';
  const detailTemplate=form.elements.detailTemplate.value||'{message}';
  byId('preview-alert-title').textContent=fillPreviewTemplate(titleTemplate,tokens);
  byId('preview-alert-detail').textContent=fillPreviewTemplate(detailTemplate,tokens);
  document.querySelector('.preview-alert-platform').textContent=(platformLabels[platform]||platform).toUpperCase();
  document.querySelector('.preview-alert-avatar').textContent=tokens.actor.charAt(0).toUpperCase();
  const card=byId('alert-preview-card');
  card.style.backgroundColor=form.elements.cardBackgroundColor.value||'#171120';
  const fontMap={system:'"Segoe UI Variable Text","Segoe UI",Arial,sans-serif',rounded:'"Arial Rounded MT Bold","Segoe UI",Arial,sans-serif',serif:'Georgia,"Times New Roman",serif',monospace:'Consolas,"Cascadia Mono",monospace'};
  card.style.fontFamily=fontMap[form.elements.cardFontFamily.value]||fontMap.system;
  const layout=form.elements.cardLayout.value||'classic';
  const videoUrl=form.elements.backgroundVideoUrl.value;
  const imageUrl=form.elements.backgroundImageUrl.value;
  const hasMedia=Boolean(videoUrl||imageUrl);
  const mediaPlacement=hasMedia?(form.elements.cardMediaPlacement.value||'behind'):'behind';
  card.dataset.layout=layout;
  card.dataset.mediaPlacement=mediaPlacement;
  const videoWrap=document.querySelector('.preview-alert-video-wrap');
  const previewOverlay=document.querySelector('.preview-alert-video-overlay');
  const insetBox=document.querySelector('.preview-alert-media-inset');
  const bannerBox=document.querySelector('.preview-alert-media-banner');
  const avatarBox=document.querySelector('.preview-alert-avatar');
  videoWrap.innerHTML='';
  insetBox.innerHTML='';
  bannerBox.innerHTML='';
  card.style.backgroundImage='none';
  previewOverlay.classList.add('hidden');
  insetBox.classList.add('hidden');
  bannerBox.classList.add('hidden');
  const showInsetMedia=hasMedia&&mediaPlacement==='inset';
  avatarBox.classList.toggle('hidden',showInsetMedia||layout==='centered');
  if(hasMedia&&mediaPlacement==='behind'){
    if(videoUrl){videoWrap.append(buildPreviewMediaNode(videoUrl,imageUrl))}
    else{card.style.backgroundImage=`url("${imageUrl.replace(/["\\]/g,'')}")`}
    previewOverlay.classList.remove('hidden');
  }else if(showInsetMedia){
    insetBox.append(buildPreviewMediaNode(videoUrl,imageUrl));
    insetBox.classList.remove('hidden');
  }else if(hasMedia&&mediaPlacement==='below'){
    bannerBox.append(buildPreviewMediaNode(videoUrl,imageUrl));
    bannerBox.classList.remove('hidden');
  }
}
