async function uploadOverlayAsset(file,kind){if(!file)return'';const contentBase64=await new Promise((resolve,reject)=>{const reader=new FileReader();reader.addEventListener('load',()=>resolve(String(reader.result).split(',')[1]||''),{once:true});reader.addEventListener('error',()=>reject(new Error('Could not read the selected file.')),{once:true});reader.readAsDataURL(file)});const result=await api('/wizard/api/overlay-assets',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({kind,contentType:file.type,contentBase64})});return result.url}
byId('alert-profile-form').elements.customSoundFile.addEventListener('change',async(event)=>{try{const url=await uploadOverlayAsset(event.target.files?.[0],'sound');event.target.form.elements.customSoundUrl.value=url;event.target.form.elements.soundMode.value='custom';byId('alert-state').textContent='Custom sound attached locally. Stage and commit the profile to keep it.'}catch(error){event.target.value='';byId('alert-state').textContent=error.message}});
byId('alert-profile-form').elements.backgroundImageFile.addEventListener('change',async(event)=>{try{const url=await uploadOverlayAsset(event.target.files?.[0],'background');const form=event.target.form;form.elements.backgroundImageUrl.value=url;form.elements.backgroundVideoUrl.value='';form.elements.backgroundVideoFile.value='';byId('clear-background-video').classList.add('hidden');byId('alert-state').textContent='Background image attached locally. Stage and commit the profile to keep it.';renderAlertPreview()}catch(error){event.target.value='';byId('alert-state').textContent=error.message}});
byId('alert-profile-form').elements.backgroundVideoFile.addEventListener('change',async(event)=>{try{const url=await uploadOverlayAsset(event.target.files?.[0],'video');const form=event.target.form;form.elements.backgroundVideoUrl.value=url;form.elements.backgroundImageUrl.value='';form.elements.backgroundImageFile.value='';byId('clear-background-video').classList.remove('hidden');byId('alert-state').textContent='Background video attached locally. It will play with its own audio in place of the Sound setting. Stage and commit the profile to keep it.';renderAlertPreview()}catch(error){event.target.value='';byId('alert-state').textContent=error.message}});
byId('clear-background-video').addEventListener('click',()=>{const form=byId('alert-profile-form');form.elements.backgroundVideoUrl.value='';form.elements.backgroundVideoFile.value='';byId('clear-background-video').classList.add('hidden');byId('alert-state').textContent='Background video removed from this form. Stage the profile to keep the change.';renderAlertPreview()});
byId('fire-test-alert').addEventListener('click',async()=>{const form=byId('alert-profile-form');if(!state.selectedAlert||!form.checkValidity()){form.reportValidity();return}const {platform,alertType}=state.selectedAlert;const alerts=structuredClone(state.alertSettings.alerts);alerts.profiles[platform]=alerts.profiles[platform]||{};alerts.profiles[platform][alertType]=readAlertProfile(form);try{const result=await api('/wizard/api/alerts/preview',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({platform,alertType,alerts,alertDurationMs:Number(byId('alert-global-form').elements.alertDurationMs.value)})});byId('alert-state').textContent=result.accepted?`Fired the current unsaved ${platformLabels[platform]} · ${alertTypeLabels[alertType]} design to connected alert overlays.`:'No alert overlay is connected; open the Alerts URL first.'}catch(error){byId('alert-state').textContent=error.message}});
byId('alert-global-form').addEventListener('submit',async(event)=>{event.preventDefault();const data=new FormData(event.target);state.alertSettings.maxAlertQueue=Number(data.get('maxAlertQueue'));state.alertSettings.alertDurationMs=Number(data.get('alertDurationMs'));state.alertSettings.showSimulated=data.get('showSimulated')==='on';try{await stageAlerts();renderAlerts()}catch(error){byId('alert-state').textContent=error.message}});
byId('alert-profile-form').addEventListener('submit',async(event)=>{event.preventDefault();const form=event.target;if(!form.checkValidity()||!state.selectedAlert){form.reportValidity();return}const {platform,alertType}=state.selectedAlert;const profile=readAlertProfile(form);if(profile.aggregation.mode==='sum-quantity'&&!['gift','gift-subscription','cheer'].includes(alertType)){byId('alert-state').textContent='Quantity aggregation is available only for gifts, gift subscriptions, and cheers/bits.';return}state.alertSettings.alerts.profiles[platform]=state.alertSettings.alerts.profiles[platform]||{};state.alertSettings.alerts.profiles[platform][alertType]=profile;try{await stageAlerts();selectAlertProfile(platform,alertType);byId('alert-state').textContent='Alert profile staged. Commit and restart StreamBridge to apply it.'}catch(error){byId('alert-state').textContent=error.message}});
byId('reset-alert-profile').addEventListener('click',async()=>{if(!state.selectedAlert)return;const {platform,alertType}=state.selectedAlert;if(!confirm(`Reset ${platformLabels[platform]} · ${alertTypeLabels[alertType]} to its default alert presentation?`))return;if(state.alertSettings.alerts.profiles[platform])delete state.alertSettings.alerts.profiles[platform][alertType];try{await stageAlerts();selectAlertProfile(platform,alertType);byId('alert-state').textContent='Reset to the default alert presentation and staged. Commit and restart StreamBridge to apply it.'}catch(error){byId('alert-state').textContent=error.message;selectAlertProfile(platform,alertType)}});
byId('clear-alert-profile').addEventListener('click',clearAlertProfile);
byId('reward-admin-form').addEventListener('submit',async(event)=>{event.preventDefault();const form=event.target;if(!form.checkValidity()){form.reportValidity();return}const data=new FormData(form);const platform=String(data.get('platform'));const operation=String(data.get('operation'));const rewardId=String(data.get('rewardId')||'').trim();const redemptionId=String(data.get('redemptionId')||'').trim();const status=byId('reward-admin-state');if((operation==='fulfill'||operation==='cancel')&&!redemptionId){status.textContent='Fulfill and cancel require the exact redemption ID.';return}if(!confirm(`Run Twitch reward operation "${operation}" on reward ${rewardId}? This changes the live reward in Streamer.bot.`))return;status.setAttribute('aria-busy','true');status.textContent='Requesting documented Twitch reward operation…';try{const result=await api('/wizard/api/rewards/administer',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({platform,operation,rewardId,...(redemptionId?{redemptionId}:{}),approvedByCreator:true})});status.textContent=result.available?`${result.operation} requested for reward ${result.rewardId}. Check Streamer.bot Action History to confirm completion.`:`Reward operation unavailable: ${result.error}`;if(result.available){rememberRecentReward(platform,rewardId);form.reset()}}catch(error){status.textContent=error.message}finally{status.removeAttribute('aria-busy')}});
const RECENT_REWARDS_KEY='thsv-recent-rewards';
function loadRecentRewards(){try{return JSON.parse(localStorage.getItem(RECENT_REWARDS_KEY)||'[]')}catch{return[]}}
function saveRecentRewards(list){try{localStorage.setItem(RECENT_REWARDS_KEY,JSON.stringify(list.slice(0,8)))}catch{/* localStorage may be unavailable; the quick-select list is a convenience, not required. */}}
function renderRecentRewards(){const list=loadRecentRewards();const host=byId('recent-rewards');if(!list.length){host.innerHTML='';return}host.innerHTML=`<strong class="preview-label">Recent reward IDs</strong><div class="recent-rewards-chips">${list.map((entry,index)=>`<button type="button" data-recent-reward="${index}">${safe(platformLabels[entry.platform]||entry.platform)} · ${safe(entry.rewardId.slice(0,8))}…</button>`).join('')}</div>`;host.querySelectorAll('[data-recent-reward]').forEach((button)=>button.addEventListener('click',()=>{const entry=list[Number(button.dataset.recentReward)];if(!entry)return;const form=byId('reward-admin-form');form.elements.platform.value=entry.platform;form.elements.rewardId.value=entry.rewardId;form.elements.rewardId.focus()}))}
function rememberRecentReward(platform,rewardId){const list=loadRecentRewards().filter((entry)=>!(entry.platform===platform&&entry.rewardId===rewardId));list.unshift({platform,rewardId});saveRecentRewards(list);renderRecentRewards()}
renderRecentRewards();
